// // This comment suggests the decoder is a 16-to-4 encoder
module decoder_4to16 (  
    input [3:0] A,  
    output reg [15:0] Y  
);  
    always @(*) begin  
        Y = 16'b0; // Reset all outputs  
        Y[A] = 1'b1; // Activate the output corresponding to the input value  
    end  
endmodule
